  newnet->hidden_delta = alloc_1d_dbl(n_hidden + 1);
  newnet->output_delta = alloc_1d_dbl(n_out + 1);
  newnet->target = alloc_1d_dbl(n_out + 1);

  newnet->input_weights_flat = alloc_1d_dbl((n_in + 1) * (n_hidden + 1));
  newnet->hidden_weights_flat = alloc_1d_dbl((n_hidden + 1) * (n_out + 1));

  newnet->input_prev_weights_flat = alloc_1d_dbl((n_in + 1) * (n_hidden + 1));
  newnet->hidden_prev_weights_flat = alloc_1d_dbl((n_hidden + 1) * (n_out + 1));

  newnet->input_weights_cols = n_hidden + 1;
  newnet->hidden_weights_cols = n_out + 1;
  newnet->input_prev_weights_cols = n_hidden + 1;
  newnet->hidden_prev_weights_cols = n_out + 1;

  return (newnet);
}

