  free((char *) net);
}

BPNN *bpnn_create(int n_in, int n_hidden, int n_out) {
  BPNN *newnet;
  newnet = bpnn_internal_create(n_in, n_hidden, n_out);

#ifdef INITZERO
  bpnn_zero_weights_flat(newnet->input_weights_flat, n_in, n_hidden);
#else
  bpnn_randomize_weights_flat(newnet->input_weights_flat, n_in, n_hidden);
#endif
  bpnn_randomize_weights_flat(newnet->hidden_weights_flat, n_hidden, n_out);
  bpnn_zero_weights_flat(newnet->input_prev_weights_flat, n_in, n_hidden);
  bpnn_zero_weights_flat(newnet->hidden_prev_weights_flat, n_hidden, n_out);
  bpnn_randomize_row(newnet->target, n_out);
  return (newnet);
}

__global__ void layerforward_kernel(float *l1, float *l2, float *conn, int n1, int n2) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j >= 1 && j <= n2) {
    float sum = 0.0;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k * (n2 + 1) + j] * l1[k];
    }
    l2[j] = 1.0 / (1.0 + exp(-sum));
  }
}

void bpnn_layerforward(float *l1, float *l2, float *conn, int n1, int n2) {
  l1[0] = 1.0;
  int threads_per_block = 256;
  int num_blocks = (n2 + threads_per_block - 1) / threads_per_block;
  layerforward_kernel<<<num_blocks, threads_per_block>>>(l1, l2, conn, n1, n2);
  cudaDeviceSynchronize();
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float *who, int who_cols, float *hidden, float *err) {
  int j, k;
  float h, sum, errsum;
  errsum = 0.0;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j * who_cols + k];
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

__global__ void adjust_weights_kernel(float *delta, float *ly, float *w, float *oldw, int ndelta, int nly, int w_cols) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j >= 1 && j <= ndelta) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * w_cols + j]));
      w[k * w_cols + j] += new_dw;
      oldw[k * w_cols + j] = new_dw;
    }
  }
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float *w, float *oldw, int w_cols) {
  ly[0] = 1.0;
  int threads_per_block = 256;
  int num_blocks = (ndelta + threads_per_block - 1) / threads_per_block;
  adjust_weights_kernel<<<num_blocks, threads_per_block>>>(delta, ly, w, oldw, ndelta, nly, w_cols);
  cudaDeviceSynchronize();
}

void bpnn_feedforward(BPNN *net) {
  int in, hid, out;
  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights_flat, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights_flat, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh) {
  int in, hid, out;
  float out_err, hid_err;
  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights_flat, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights_flat, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights_flat, net->hidden_weights_cols, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights_flat, net->hidden_prev_weights_flat, net->hidden_weights_cols);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights_flat, net->input_prev_weights_flat, net->input_weights_cols);
}

